// Split comma-separated queries into individual items
const config = $input.first().json;
const queries = config.queries.split(',').map(q => q.trim());

return queries.map(query => ({
  json: {
    searchQuery: query,
    resumeFileId: config.resumeFileId,
    recipientEmail: config.recipientEmail,
    jobsPerQuery: parseInt(config.jobsPerQuery)
  }
}));

const items = $input.all().map(i => i.json);
const searchQuery = $('Split Into Individual Queries').first().json.searchQuery;
if (!items || items.length === 0) {
  return [{ json: { error: 'No jobs found', searchQuery } }];
}
return items.map(job => ({
  json: {
    searchQuery: searchQuery,
    jobTitle: job.title || 'N/A',
    company: job.companyName || job.company || 'N/A',
    location: job.location || 'N/A',
    jobUrl: job.url || job.link || '#',
    postedDate: job.postedAt || job.publishedAt || 'N/A',
    description: (job.description || job.descriptionText || 'No description available').substring(0, 4000),
    seniorityLevel: job.seniorityLevel || 'N/A',
    employmentType: job.employmentType || 'N/A',
    resumeFileId: $('Config - Search Queries & Settings').first().json.resumeFileId,
    recipientEmail: $('Config - Search Queries & Settings').first().json.recipientEmail
  }
}));

// Merge resume text back with job data
const resumeText = $input.first().json.data || $input.first().json.text || 'Resume text extraction failed';
const jobs = $('Rank & Filter Top Jobs').all();

return jobs.map(job => ({
  json: {
    ...job.json,
    resumeText: typeof resumeText === 'string' ? resumeText : JSON.stringify(resumeText)
  }
}));

// Extract tailored resume from Gemini response
const geminiResponse = $input.first().json;
let tailoredResume = '';

try {
  tailoredResume = geminiResponse.candidates[0].content.parts[0].text;
} catch (e) {
  tailoredResume = 'ERROR: Failed to generate tailored resume. Raw response: ' + JSON.stringify(geminiResponse).substring(0, 500);
}

const jobData = $('Loop Over Items').first().json;

return [{
  json: {
    jobTitle: jobData.jobTitle,
    company: jobData.company,
    location: jobData.location,
    jobUrl: jobData.jobUrl,
    postedDate: jobData.postedDate,
    searchQuery: jobData.searchQuery,
    tailoredResume: tailoredResume,
    recipientEmail: jobData.recipientEmail || .DIGEST_RECIPIENT_EMAIL || 'example@example.com',
    docTitle: `Resume - ${jobData.company} - ${jobData.jobTitle} - ${new Date().toISOString().split('T')[0]}`
  }
}];

// Build link item for summary table
const jobData = $('Parse Tailored Resume').first().json;
const docId = $('Create Google Doc').first().json.documentId;

return [{
  json: {
    company: jobData.company,
    jobTitle: jobData.jobTitle,
    location: jobData.location,
    category: jobData.searchQuery,
    postedDate: jobData.postedDate,
    jobUrl: jobData.jobUrl,
    resumeDocUrl: `https://docs.google.com/document/d/${docId}/edit`,
    docTitle: jobData.docTitle
  }
}];

// Build HTML email summary
const allJobs = $input.first().json.allJobs;
const now = new Date().toLocaleDateString('en-US', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

const categories = {};
for (const job of allJobs) {
  if (!categories[job.category]) categories[job.category] = [];
  categories[job.category].push(job);
}

let tableRows = '';
for (const [category, jobs] of Object.entries(categories)) {
  tableRows += `<tr><td colspan="6" style="background:#1a1a2e;color:#fff;padding:10px;font-weight:bold;font-size:14px;">${category}</td></tr>`;
  for (const job of jobs) {
    tableRows += `
      <tr style="border-bottom:1px solid #eee;">
        <td style="padding:8px;">${job.company}</td>
        <td style="padding:8px;">${job.jobTitle}</td>
        <td style="padding:8px;">${job.location}</td>
        <td style="padding:8px;">${job.postedDate}</td>
        <td style="padding:8px;"><a href="${job.jobUrl}" style="color:#0066cc;">Job Link</a></td>
        <td style="padding:8px;"><a href="${job.resumeDocUrl}" style="color:#28a745;font-weight:bold;">Resume Doc</a></td>
      </tr>`;
  }
}

const html = `
<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto;">
  <div style="background:#1a1a2e;color:#fff;padding:20px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0;font-size:22px;">Your ATS Resumes Are Ready (${allJobs.length})</h1>
    <p style="margin:5px 0 0;opacity:0.8;">Generated: ${now}</p>
  </div>

  <table style="width:100%;border-collapse:collapse;background:#fff;">
    <thead>
      <tr style="background:#f5f5f5;">
        <th style="padding:10px;text-align:left;">Company</th>
        <th style="padding:10px;text-align:left;">Role</th>
        <th style="padding:10px;text-align:left;">Location</th>
        <th style="padding:10px;text-align:left;">Posted</th>
        <th style="padding:10px;text-align:left;">Job</th>
        <th style="padding:10px;text-align:left;">Resume</th>
      </tr>
    </thead>
    <tbody>
      ${tableRows}
    </tbody>
  </table>

  <div style="background:#f0f7ff;padding:15px;border-radius:0 0 8px 8px;margin-top:2px;">
    <p style="margin:0;font-size:13px;color:#555;">Tip: Review each tailored resume before applying. The AI preserves your real experience but reorders and keywords-optimizes for each role.</p>
  </div>
</div>`;

return [{
  json: {
    emailHtml: html,
    subject: `Daily Job Resumes Ready (${allJobs.length}) - ${new Date().toISOString().split('T')[0]}`,
    recipientEmail: allJobs[0]?.recipientEmail || $('Config - Search Queries & Settings').first().json.recipientEmail,
    jobCount: allJobs.length
  }
}];

// Error handler - send notification on failure
const error = $input.first().json;
return [{
  json: {
    errorMessage: JSON.stringify(error).substring(0, 1000),
    timestamp: new Date().toISOString()
  }
}];

