const items = $input.all().map(i => i.json);
const skillKeywords = [
  'python', 'ros', 'autonomous', 'robotics', 'machine learning', 'ai', 'ml',
  'computer vision', 'deep learning', 'pytorch', 'tensorflow', 'opencv',
  'plc', 'automation', 'scada', 'c++', 'matlab', 'simulink', 'embedded',
  'lidar', 'sensor fusion', 'slam', 'path planning', 'neural network',
  'internship', 'intern', 'entry level'
];

function scoreJob(job) {
  const text = `${job.jobTitle} ${job.description} ${job.seniorityLevel} ${job.employmentType}`.toLowerCase();

  // ONLY penalize if PhD is strictly in the JOB TITLE!
  // If it's just in the description ("Masters or PhD"), it's fine!
  if (job.jobTitle.toLowerCase().includes('phd') || job.jobTitle.toLowerCase().includes('ph.d')) {
    return -100;
  }

  let score = 0;
  for (const kw of skillKeywords) {
    if (text.includes(kw)) score += 1;
  }
  if (text.includes('intern')) score += 3;
  if (job.seniorityLevel && job.seniorityLevel.toLowerCase().includes('intern')) score += 3;
  return score;
}

for (let job of items) {
  job._score = scoreJob(job);
}

const validJobs = items.filter(j => j._score > -50);
const sortedJobs = validJobs.sort((a, b) => b._score - a._score);
const topJobs = sortedJobs.slice(0, 18);
return topJobs.map(job => ({ json: job }));
